export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other';

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other'];

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#e74c3c',
  transport: '#3498db',
  housing: '#2ecc71',
  entertainment: '#f39c12',
  utilities: '#9b59b6',
  other: '#95a5a6',
};

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
};

export type Expense = {
  id: string;
  amount: number;
  category: Category;
  date: string; // ISO date string YYYY-MM-DD
  notes: string;
  createdAt: string;
};

export type ExpenseFilter = {
  startDate?: string;
  endDate?: string;
  category?: Category;
};

export type CategorySummary = {
  category: Category;
  total: number;
  count: number;
  percentage: number;
};

export type MonthlySummary = {
  month: string; // YYYY-MM
  total: number;
  categories: CategorySummary[];
};

import type { Expense, ExpenseFilter, Category, MonthlySummary, CategorySummary } from './types';
import { CATEGORIES } from './types';

const DATA_PATH = 'data/expenses.json';

const generateId = (): string => {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).slice(2, 8);
  return `${timestamp}-${random}`;
};

const readExpenses = async (): Promise<Expense[]> => {
  try {
    const file = Bun.file(DATA_PATH);
    const exists = await file.exists();
    if (!exists) return [];
    return await file.json();
  } catch {
    return [];
  }
};

const writeExpenses = async (expenses: Expense[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(expenses, null, 2));
};

export const addExpense = async (params: {
  amount: number;
  category: Category;
  date: string;
  notes?: string;
}): Promise<Expense> => {
  const expenses = await readExpenses();
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(params.amount * 100) / 100,
    category: params.category,
    date: params.date,
    notes: params.notes ?? '',
    createdAt: new Date().toISOString(),
  };
  expenses.push(expense);
  await writeExpenses(expenses);
  return expense;
};

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses();
  const index = expenses.findIndex((e) => e.id === id);
  if (index === -1) return false;
  expenses.splice(index, 1);
  await writeExpenses(expenses);
  return true;
};

export const getExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const expenses = await readExpenses();
  let filtered = expenses;

  if (filter?.startDate) {
    filtered = filtered.filter((e) => e.date >= filter.startDate!);
  }
  if (filter?.endDate) {
    filtered = filtered.filter((e) => e.date <= filter.endDate!);
  }
  if (filter?.category) {
    filtered = filtered.filter((e) => e.category === filter.category);
  }

  return filtered.sort((a, b) => b.date.localeCompare(a.date));
};

export const getMonthlySummary = async (month: string): Promise<MonthlySummary> => {
  const expenses = await readExpenses();
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month));

  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0);

  const categories: CategorySummary[] = CATEGORIES.map((category) => {
    const catExpenses = monthExpenses.filter((e) => e.category === category);
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0);
    return {
      category,
      total: Math.round(catTotal * 100) / 100,
      count: catExpenses.length,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
    };
  }).filter((c) => c.count > 0);

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  };
};

export const getAvailableMonths = async (): Promise<string[]> => {
  const expenses = await readExpenses();
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)));
  return Array.from(months).sort().reverse();
};

import type { CategorySummary } from './types';
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types';
import { h } from '@plaited/template';

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = {
    x: cx + r * Math.cos(startAngle),
    y: cy + r * Math.sin(startAngle),
  };
  const end = {
    x: cx + r * Math.cos(endAngle),
    y: cy + r * Math.sin(endAngle),
  };
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0;
  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ');
};

export const renderPieChart = (categories: CategorySummary[], size: number = 240): string => {
  const cx = size / 2;
  const cy = size / 2;
  const r = size / 2 - 10;
  const legendX = size + 20;
  const totalWidth = size + 200;
  const totalHeight = Math.max(size, categories.length * 28 + 20);

  if (categories.length === 0) {
    return h(
      'svg',
      { width: String(totalWidth), height: '60', xmlns: 'http://www.w3.org/2000/svg' },
      h(
        'text',
        { x: '10', y: '30', fill: '#888', 'font-size': '14', 'font-family': 'system-ui, sans-serif' },
        'No expenses to chart',
      ),
    ) as string;
  }

  if (categories.length === 1) {
    const cat = categories[0];
    const color = CATEGORY_COLORS[cat.category];
    const label = CATEGORY_LABELS[cat.category];
    return h(
      'svg',
      { width: String(totalWidth), height: String(totalHeight), xmlns: 'http://www.w3.org/2000/svg' },
      h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: color }),
      h('rect', { x: String(legendX), y: '10', width: '16', height: '16', fill: color, rx: '3' }),
      h(
        'text',
        { x: String(legendX + 22), y: '23', fill: '#333', 'font-size': '13', 'font-family': 'system-ui, sans-serif' },
        `${label}: 100%`,
      ),
    ) as string;
  }

  let currentAngle = -Math.PI / 2;
  const slices: string[] = [];

  for (const cat of categories) {
    const sliceAngle = (cat.percentage / 100) * 2 * Math.PI;
    const color = CATEGORY_COLORS[cat.category];
    slices.push(
      h('path', {
        d: describeArc(cx, cy, r, currentAngle, currentAngle + sliceAngle),
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      }) as string,
    );
    currentAngle += sliceAngle;
  }

  const legendItems: string[] = categories.map((cat, i) => {
    const color = CATEGORY_COLORS[cat.category];
    const label = CATEGORY_LABELS[cat.category];
    const y = 10 + i * 28;
    return [
      h('rect', { x: String(legendX), y: String(y), width: '16', height: '16', fill: color, rx: '3' }),
      h(
        'text',
        {
          x: String(legendX + 22),
          y: String(y + 13),
          fill: '#333',
          'font-size': '13',
          'font-family': 'system-ui, sans-serif',
        },
        `${label}: ${cat.percentage}%`,
      ),
    ].join('');
  });

  return h(
    'svg',
    { width: String(totalWidth), height: String(totalHeight), xmlns: 'http://www.w3.org/2000/svg' },
    ...slices,
    ...legendItems,
  ) as string;
};

import type { Expense } from './types';
import { CATEGORY_LABELS } from './types';

const escapeCSV = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

export const exportCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes';
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) =>
      [
        e.date,
        escapeCSV(CATEGORY_LABELS[e.category]),
        e.amount.toFixed(2),
        escapeCSV(e.notes),
      ].join(','),
    );
  return [header, ...rows].join('\n');
};

