  const catRows = summary.categories
    .sort((a, b) => b.total - a.total)
    .map((c) =>
      h(
        'div',
        { style: styleStr(styles.summaryRow) },
        h(
          'div',
          { style: 'display:flex;align-items:center;gap:8px' },
          h('span', { style: styleStr(styles.badge(CATEGORY_COLORS[c.category])) }, CATEGORY_LABELS[c.category]),
          h('span', { style: 'font-size:13px;color:#888' }, `${c.count} expense${c.count === 1 ? '' : 's'}`),
        ),
        h(
          'div',
          { style: 'text-align:right' },
          h('span', { style: 'font-weight:600' }, `$${c.total.toFixed(2)}`),
          h('span', { style: 'font-size:12px;color:#888;margin-left:8px' }, `${c.percentage}%`),
        ),
      ),
    );

  const pieChart = renderPieChart(summary.categories);

  return h(
    'div',
    { style: styleStr(styles.card) },
    h(
      'div',
      { style: 'display:flex;justify-content:space-between;align-items:center;margin-bottom:16px' },
      h('div', { style: styleStr(styles.cardTitle) }, `Summary: ${monthLabel}`),
    ),
    h('div', { style: styleStr(styles.totalBanner) }, `$${summary.total.toFixed(2)}`),
    h('div', { style: styleStr(styles.totalLabel) + ';margin-bottom:20px' }, 'Total Spent'),
    h('div', { style: 'display:flex;gap:40px;flex-wrap:wrap' },
      h('div', { style: 'flex:1;min-width:240px' }, pieChart),
      h('div', { style: 'flex:1;min-width:260px' }, ...catRows),
    ),
  ) as string;
};

