export type MarkerCategory = 'default' | 'restaurant' | 'park' | 'shop' | 'landmark' | 'custom';

export type MapMarker = {
  id: string;
  lat: number;
  lng: number;
  title: string;
  description: string;
  category: MarkerCategory;
};

export type MapCircle = {
  id: string;
  lat: number;
  lng: number;
  radius: number;
  color: string;
  title: string;
};

export const CATEGORY_COLORS: Record<MarkerCategory, string> = {
  default: '#2196F3',
  restaurant: '#FF5722',
  park: '#4CAF50',
  shop: '#9C27B0',
  landmark: '#FF9800',
  custom: '#607D8B',
};

export const CATEGORY_LABELS: Record<MarkerCategory, string> = {
  default: 'Default',
  restaurant: 'Restaurant',
  park: 'Park',
  shop: 'Shop',
  landmark: 'Landmark',
  custom: 'Custom',
};

import { renderPage } from './render';
import type { MapMarker, MapCircle } from './types';

const DATA_DIR = './data';
const MARKERS_FILE = `${DATA_DIR}/markers.json`;
const CIRCLES_FILE = `${DATA_DIR}/circles.json`;

const loadJSON = async <T>(path: string): Promise<T[]> => {
  try {
    return await Bun.file(path).json();
  } catch {
    return [];
  }
};

const saveJSON = async <T>(path: string, data: T[]): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

const generateId = (): string => crypto.randomUUID();

const handleMarkers = async (req: Request, path: string): Promise<Response | null> => {
  if (path === '/api/markers' && req.method === 'GET') {
    const markers = await loadJSON<MapMarker>(MARKERS_FILE);
    return Response.json(markers);
  }

  if (path === '/api/markers' && req.method === 'POST') {
    const body = (await req.json()) as Omit<MapMarker, 'id'>;
    const markers = await loadJSON<MapMarker>(MARKERS_FILE);
    const marker: MapMarker = { id: generateId(), ...body };
    markers.push(marker);
    await saveJSON(MARKERS_FILE, markers);
    return Response.json(marker, { status: 201 });
  }

  if (path.startsWith('/api/markers/') && req.method === 'DELETE') {
    const id = path.slice('/api/markers/'.length);
    const markers = await loadJSON<MapMarker>(MARKERS_FILE);
    const filtered = markers.filter((m) => m.id !== id);
    await saveJSON(MARKERS_FILE, filtered);
    return Response.json({ ok: true });
  }

  return null;
};

const handleCircles = async (req: Request, path: string): Promise<Response | null> => {
  if (path === '/api/circles' && req.method === 'GET') {
    const circles = await loadJSON<MapCircle>(CIRCLES_FILE);
    return Response.json(circles);
  }

  if (path === '/api/circles' && req.method === 'POST') {
    const body = (await req.json()) as Omit<MapCircle, 'id'>;
    const circles = await loadJSON<MapCircle>(CIRCLES_FILE);
    const circle: MapCircle = { id: generateId(), ...body };
    circles.push(circle);
    await saveJSON(CIRCLES_FILE, circles);
    return Response.json(circle, { status: 201 });
  }

  if (path.startsWith('/api/circles/') && req.method === 'DELETE') {
    const id = path.slice('/api/circles/'.length);
    const circles = await loadJSON<MapCircle>(CIRCLES_FILE);
    const filtered = circles.filter((c) => c.id !== id);
    await saveJSON(CIRCLES_FILE, filtered);
    return Response.json({ ok: true });
  }

  return null;
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;

    if (path === '/' && req.method === 'GET') {
      const html = renderPage();
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    if (path === '/client.js' && req.method === 'GET') {
      const js = await Bun.file('./client.js').text();
      return new Response(js, {
        headers: { 'Content-Type': 'application/javascript; charset=utf-8' },
      });
    }

    const markerRes = await handleMarkers(req, path);
    if (markerRes) return markerRes;

    const circleRes = await handleCircles(req, path);
    if (circleRes) return circleRes;

    return new Response('Not Found', { status: 404 });
  },
});

