(function () {
  "use strict";

  var COLORS = {
    default: "#2196F3",
    restaurant: "#FF5722",
    park: "#4CAF50",
    shop: "#9C27B0",
    landmark: "#FF9800",
    custom: "#607D8B",
  };

  var LABELS = {
    default: "Default",
    restaurant: "Restaurant",
    park: "Park",
    shop: "Shop",
    landmark: "Landmark",
    custom: "Custom",
  };

  var markers = [];
  var circles = [];
  var leafletMarkers = {};
  var leafletCircles = {};
  var activeFilters = new Set(Object.keys(COLORS));
  var mode = "default";

  var map = L.map("map").setView([51.505, -0.09], 13);

  L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
    attribution:
      '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(map);

  var createMarkerIcon = function (color) {
    var svg =
      '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 36" width="24" height="36">' +
      '<path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 24 12 24s12-15 12-24C24 5.4 18.6 0 12 0z" fill="' +
      color +
      '" stroke="#fff" stroke-width="1"/>' +
      '<circle cx="12" cy="12" r="5" fill="#fff"/>' +
      "</svg>";
    return L.divIcon({
      html: svg,
      className: "custom-div-icon",
      iconSize: [24, 36],
      iconAnchor: [12, 36],
      popupAnchor: [0, -36],
    });
  };

  var apiGet = function (url) {
    return fetch(url).then(function (r) {
      return r.json();
    });
  };

  var apiPost = function (url, data) {
    return fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    }).then(function (r) {
      return r.json();
    });
  };

  var apiDel = function (url) {
    return fetch(url, { method: "DELETE" }).then(function (r) {
      return r.json();
    });
  };

  var escapeHtml = function (str) {
    var div = document.createElement("div");
    div.textContent = str;
    return div.innerHTML;
  };

  var addMarkerToMap = function (marker) {
    var color = COLORS[marker.category] || COLORS.default;
    var icon = createMarkerIcon(color);
    var lMarker = L.marker([marker.lat, marker.lng], { icon: icon })
      .bindPopup(
        "<strong>" +
          escapeHtml(marker.title) +
          "</strong><br>" +
          escapeHtml(marker.description || "") +
          "<br><em>" +
          escapeHtml(LABELS[marker.category] || "Default") +
          "</em>"
      )
      .addTo(map);
    leafletMarkers[marker.id] = lMarker;
    if (!activeFilters.has(marker.category)) {
      map.removeLayer(lMarker);
    }
  };

  var addCircleToMap = function (circle) {
    var lCircle = L.circle([circle.lat, circle.lng], {
      radius: circle.radius,
      color: circle.color,
      fillColor: circle.color,
      fillOpacity: 0.15,
      weight: 2,
    })
      .bindPopup(
        "<strong>" +
          escapeHtml(circle.title || "Circle") +
          "</strong><br>Radius: " +
          circle.radius +
          "m"
      )
      .addTo(map);
    leafletCircles[circle.id] = lCircle;
  };

  var renderMarkerList = function () {
    var list = document.getElementById("marker-list");
    if (!list) return;
    list.innerHTML = "";
    var filtered = markers.filter(function (m) {
      return activeFilters.has(m.category);
    });
    if (filtered.length === 0) {
      list.innerHTML =
        '<div class="empty-msg">No markers yet. Click "Add Marker" then click the map.</div>';
      return;
    }
    filtered.forEach(function (marker) {
      var item = document.createElement("div");
      item.className = "marker-item";
      item.innerHTML =
        '<span class="marker-dot" style="background:' +
        (COLORS[marker.category] || COLORS.default) +
        '"></span>' +
        '<div class="marker-info">' +
        '<div class="marker-title">' +
        escapeHtml(marker.title) +
        "</div>" +
        '<div class="marker-desc">' +
        escapeHtml(marker.description || "No description") +
        "</div>" +
        "</div>" +
        '<button class="delete-btn" data-id="' +
        marker.id +
        '" title="Delete">&times;</button>';

      var infoEl = item.querySelector(".marker-info");
      if (infoEl) {
        infoEl.addEventListener("click", function () {
          map.flyTo([marker.lat, marker.lng], 16);
          var lm = leafletMarkers[marker.id];
          if (lm) lm.openPopup();
        });
      }

      var deleteEl = item.querySelector(".delete-btn");
      if (deleteEl) {
        deleteEl.addEventListener("click", function (e) {
          e.stopPropagation();
          apiDel("/api/markers/" + marker.id).then(function () {
            if (leafletMarkers[marker.id]) {
              map.removeLayer(leafletMarkers[marker.id]);
              delete leafletMarkers[marker.id];
            }
            markers = markers.filter(function (m) {
              return m.id !== marker.id;
            });
            renderMarkerList();
          });
        });
      }

      list.appendChild(item);
    });
  };

  var renderFilters = function () {
    var container = document.getElementById("category-filters");
    if (!container) return;
    container.innerHTML = "";
    Object.keys(LABELS).forEach(function (key) {
      var wrapper = document.createElement("label");
      wrapper.className = "filter-label";
      wrapper.innerHTML =
        '<input type="checkbox" value="' +
        key +
        '"' +
        (activeFilters.has(key) ? " checked" : "") +
        ">" +
        '<span class="filter-dot" style="background:' +
        COLORS[key] +
        '"></span> ' +
        LABELS[key];

      var checkbox = wrapper.querySelector("input");
      if (checkbox) {
        checkbox.addEventListener("change", function (e) {
          if (e.target.checked) {
            activeFilters.add(key);
          } else {
            activeFilters.delete(key);
          }
          markers.forEach(function (m) {
            var lm = leafletMarkers[m.id];
            if (!lm) return;
            if (activeFilters.has(m.category)) {
              map.addLayer(lm);
            } else {
              map.removeLayer(lm);
            }
          });
          renderMarkerList();
        });
      }

      container.appendChild(wrapper);
    });
  };

  var setMode = function (newMode) {
    mode = newMode;
    var addBtn = document.getElementById("add-marker-btn");
    var circleBtn = document.getElementById("draw-circle-btn");
    var mapEl = document.getElementById("map");
    if (addBtn) {
      if (mode === "add-marker") addBtn.classList.add("active");
      else addBtn.classList.remove("active");
    }
    if (circleBtn) {
      if (mode === "draw-circle") circleBtn.classList.add("active");
      else circleBtn.classList.remove("active");
    }
    if (mapEl) {
      if (mode !== "default") mapEl.classList.add("crosshair");
      else mapEl.classList.remove("crosshair");
    }
  };

  var addMarkerBtn = document.getElementById("add-marker-btn");
  if (addMarkerBtn) {
    addMarkerBtn.addEventListener("click", function () {
      setMode(mode === "add-marker" ? "default" : "add-marker");
    });
  }

  var drawCircleBtn = document.getElementById("draw-circle-btn");
  if (drawCircleBtn) {
    drawCircleBtn.addEventListener("click", function () {
      setMode(mode === "draw-circle" ? "default" : "draw-circle");
    });
  }

  map.on("click", function (e) {
    if (mode === "add-marker") {
      var modal = document.getElementById("marker-modal");
      if (modal) {
        modal.classList.remove("hidden");
        modal.dataset.lat = String(e.latlng.lat);
        modal.dataset.lng = String(e.latlng.lng);
      }
      setMode("default");
    } else if (mode === "draw-circle") {
      var circleModal = document.getElementById("circle-modal");
      if (circleModal) {
        circleModal.classList.remove("hidden");
        circleModal.dataset.lat = String(e.latlng.lat);
        circleModal.dataset.lng = String(e.latlng.lng);
      }
      setMode("default");
    }
  });

  var markerForm = document.getElementById("marker-form");
  if (markerForm) {
    markerForm.addEventListener("submit", function (e) {
      e.preventDefault();
      var modal = document.getElementById("marker-modal");
      var form = e.target;
      var formData = new FormData(form);
      var data = {
        lat: parseFloat(modal.dataset.lat),
        lng: parseFloat(modal.dataset.lng),
        title: formData.get("markerTitle") || "Untitled",
        description: formData.get("description") || "",
        category: formData.get("category") || "default",
      };
      apiPost("/api/markers", data).then(function (marker) {
        markers.push(marker);
        addMarkerToMap(marker);
        renderMarkerList();
        form.reset();
        modal.classList.add("hidden");
      });
    });
  }

  var cancelMarkerBtn = document.getElementById("cancel-marker");
  if (cancelMarkerBtn) {
    cancelMarkerBtn.addEventListener("click", function () {
      var modal = document.getElementById("marker-modal");
      var form = document.getElementById("marker-form");
      if (modal) modal.classList.add("hidden");
      if (form) form.reset();
    });
  }

  var circleForm = document.getElementById("circle-form");
  if (circleForm) {
    circleForm.addEventListener("submit", function (e) {
      e.preventDefault();
      var modal = document.getElementById("circle-modal");
      var form = e.target;
      var formData = new FormData(form);
      var data = {
        lat: parseFloat(modal.dataset.lat),
        lng: parseFloat(modal.dataset.lng),
        radius: parseFloat(formData.get("radius")) || 500,
        color: formData.get("color") || "#2196F3",
        title: formData.get("circleTitle") || "",
      };
      apiPost("/api/circles", data).then(function (circle) {
        circles.push(circle);
        addCircleToMap(circle);
        form.reset();
        modal.classList.add("hidden");
      });
    });
  }

  var cancelCircleBtn = document.getElementById("cancel-circle");
  if (cancelCircleBtn) {
    cancelCircleBtn.addEventListener("click", function () {
      var modal = document.getElementById("circle-modal");
      var form = document.getElementById("circle-form");
      if (modal) modal.classList.add("hidden");
      if (form) form.reset();
    });
  }

  var searchInput = document.getElementById("search-input");
  var searchBtn = document.getElementById("search-btn");

  var doSearch = function () {
    var query = searchInput ? searchInput.value.trim() : "";
    if (!query) return;
    fetch(
      "https://nominatim.openstreetmap.org/search?format=json&q=" +
        encodeURIComponent(query) +
        "&limit=1"
    )
      .then(function (r) {
        return r.json();
      })
      .then(function (results) {
        if (results.length > 0) {
          var lat = parseFloat(results[0].lat);
          var lon = parseFloat(results[0].lon);
          map.flyTo([lat, lon], 14);
        }
      })
      .catch(function (err) {
        console.error("Search failed:", err);
      });
  };

  if (searchBtn) {
    searchBtn.addEventListener("click", doSearch);
  }
  if (searchInput) {
    searchInput.addEventListener("keydown", function (e) {
      if (e.key === "Enter") doSearch();
    });
  }

  var init = function () {
    apiGet("/api/markers").then(function (data) {
      markers = data;
      markers.forEach(addMarkerToMap);
      renderMarkerList();
    });
    apiGet("/api/circles").then(function (data) {
      circles = data;
      circles.forEach(addCircleToMap);
    });
    renderFilters();
  };

  init();
})();

