export type Frequency = 'daily' | 'weekly';

export type Habit = {
  id: string;
  name: string;
  frequency: Frequency;
  createdAt: string;
};

export type Completion = {
  habitId: string;
  date: string; // YYYY-MM-DD
};

export type HabitWithStatus = Habit & {
  completedToday: boolean;
};

export type WeekDay = {
  date: string; // YYYY-MM-DD
  label: string; // Mon, Tue, etc.
  isToday: boolean;
};

export type HabitWeekData = {
  habit: Habit;
  days: { date: string; completed: boolean }[];
};

import type { Habit, Completion, Frequency } from './types';

const HABITS_PATH = 'data/habits.json';
const COMPLETIONS_PATH = 'data/completions.json';

export const loadHabits = async (): Promise<Habit[]> => {
  const file = Bun.file(HABITS_PATH);
  if (!(await file.exists())) {
    await Bun.write(HABITS_PATH, '[]');
    return [];
  }
  return file.json();
};

export const saveHabits = async (habits: Habit[]): Promise<void> => {
  await Bun.write(HABITS_PATH, JSON.stringify(habits, null, 2));
};

export const loadCompletions = async (): Promise<Completion[]> => {
  const file = Bun.file(COMPLETIONS_PATH);
  if (!(await file.exists())) {
    await Bun.write(COMPLETIONS_PATH, '[]');
    return [];
  }
  return file.json();
};

export const saveCompletions = async (completions: Completion[]): Promise<void> => {
  await Bun.write(COMPLETIONS_PATH, JSON.stringify(completions, null, 2));
};

export const generateId = (): string => {
  return crypto.randomUUID();
};

export const getToday = (): string => {
  return new Date().toISOString().split('T')[0];
};

export const getWeekDates = (): string[] => {
  const today = new Date();
  const dayOfWeek = today.getDay();
  // Monday = 0, Sunday = 6
  const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(today);
  monday.setDate(today.getDate() + mondayOffset);

  const dates: string[] = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    dates.push(d.toISOString().split('T')[0]);
  }
  return dates;
};

export const getDayLabel = (dateStr: string): string => {
  const labels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const d = new Date(dateStr + 'T00:00:00');
  return labels[d.getDay()];
};

export const addHabit = async (name: string, frequency: Frequency): Promise<Habit> => {
  const habits = await loadHabits();
  const habit: Habit = {
    id: generateId(),
    name,
    frequency,
    createdAt: new Date().toISOString(),
  };
  habits.push(habit);
  await saveHabits(habits);
  return habit;
};

export const removeHabit = async (id: string): Promise<void> => {
  const habits = await loadHabits();
  const filtered = habits.filter((h) => h.id !== id);
  await saveHabits(filtered);

  const completions = await loadCompletions();
  const filteredCompletions = completions.filter((c) => c.habitId !== id);
  await saveCompletions(filteredCompletions);
};

export const toggleCompletion = async (habitId: string, date: string): Promise<boolean> => {
  const completions = await loadCompletions();
  const existing = completions.findIndex(
    (c) => c.habitId === habitId && c.date === date
  );

  if (existing >= 0) {
    completions.splice(existing, 1);
    await saveCompletions(completions);
    return false;
  } else {
    completions.push({ habitId, date });
    await saveCompletions(completions);
    return true;
  }
};

export const isCompleted = (completions: Completion[], habitId: string, date: string): boolean => {
  return completions.some((c) => c.habitId === habitId && c.date === date);
};

export const getWeeklyCompletionRate = (
  habits: Habit[],
  completions: Completion[],
  weekDates: string[]
): number => {
  if (habits.length === 0) return 0;

  let totalSlots = 0;
  let completedSlots = 0;

  for (const habit of habits) {
    const relevantDates = habit.frequency === 'daily'
      ? weekDates
      : [weekDates[weekDates.length - 1]]; // for weekly, just count once

    for (const date of relevantDates) {
      totalSlots++;
      if (isCompleted(completions, habit.id, date)) {
        completedSlots++;
      }
    }
  }

  return totalSlots > 0 ? Math.round((completedSlots / totalSlots) * 100) : 0;
};

