          const done = isCompleted(completions, habit.id, today);
          return h('div', { style: styles.habitItem },
            h('form', { method: 'POST', action: '/toggle', style: { display: 'contents' } },
              h('input', { type: 'hidden', name: 'habitId', value: habit.id }),
              h('input', { type: 'hidden', name: 'date', value: today }),
              h('button', {
                type: 'submit',
                style: done ? styles.checkboxChecked : styles.checkbox,
                'aria-label': `Toggle ${habit.name}`,
              }, done ? '\u2713' : ''),
            ),
            h('span', { style: done ? styles.habitNameDone : styles.habitName }, habit.name),
            h('span', { style: styles.frequencyBadge }, habit.frequency),
            h('form', { method: 'POST', action: '/remove', style: { display: 'contents' } },
              h('input', { type: 'hidden', name: 'habitId', value: habit.id }),
              h('button', {
                type: 'submit',
                style: styles.deleteBtn,
                'aria-label': `Delete ${habit.name}`,
              }, '\u00d7'),
            ),
          );
        })
