    habitItems,
  );
};

export const renderWeekView = (habits: Habit[], completions: Completion[]): string => {
  const weekDates = getWeekDates();
  const today = getToday();
  const rate = getWeeklyCompletionRate(habits, completions, weekDates);

  if (habits.length === 0) {
    return h('div', { style: styles.emptyState },
      h('p', {}, 'No habits to display.'),
      h('p', {}, 'Switch to Today and add some habits first!'),
    );
  }

  const dayHeaders = weekDates.map((date) => {
    const label = getDayLabel(date);
    const isToday = date === today;
    return h('div', { style: isToday ? styles.dayHeaderToday : styles.dayHeader }, label);
  });

  const habitRows = habits.map((habit) => {
    const dots = weekDates.map((date) => {
      const completed = isCompleted(completions, habit.id, date);
      const isToday = date === today;
      let dotStyle: Record<string, string>;
      if (completed && isToday) dotStyle = styles.dotTodayCompleted;
      else if (completed) dotStyle = styles.dotCompleted;
      else if (isToday) dotStyle = styles.dotToday;
      else dotStyle = styles.dotMissed;
      return h('div', { style: dotStyle });
    });

    return h('div', { style: styles.weekRow },
      h('div', { style: styles.weekHabitName }, habit.name),
      ...dots,
    );
  });

  return h('div', {},
    h('div', { style: styles.rateCard },
      h('div', { style: styles.rateNumber }, `${rate}%`),
      h('div', { style: styles.rateLabel }, 'Weekly completion rate'),
    ),
    h('div', { style: styles.weekGrid },
      h('div', { style: styles.weekHeader },
        h('div', {}, 'Habit'),
        ...dayHeaders,
      ),
      ...habitRows,
    ),
  );
};

