const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  params.forEach((value, key) => {
    result[key] = value;
  });
  return result;
};

const redirect = (path: string): Response => {
  return new Response(null, {
    status: 303,
    headers: { Location: path },
  });
};

const htmlResponse = (html: string): Response => {
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    // Today view
    if (pathname === '/' && method === 'GET') {
      const [habits, completions] = await Promise.all([loadHabits(), loadCompletions()]);
      const body = renderTodayView(habits, completions);
      return htmlResponse(renderPage('today', body));
    }

    // Week view
    if (pathname === '/week' && method === 'GET') {
      const [habits, completions] = await Promise.all([loadHabits(), loadCompletions()]);
      const body = renderWeekView(habits, completions);
      return htmlResponse(renderPage('week', body));
    }

    // Add habit
    if (pathname === '/add' && method === 'POST') {
      const form = await parseFormBody(req);
      const name = form.name?.trim();
      const frequency = form.frequency as Frequency;
      if (name && (frequency === 'daily' || frequency === 'weekly')) {
        await addHabit(name, frequency);
      }
      return redirect('/');
    }

    // Toggle completion
    if (pathname === '/toggle' && method === 'POST') {
      const form = await parseFormBody(req);
      const { habitId, date } = form;
      if (habitId && date) {
        await toggleCompletion(habitId, date);
      }
      const referer = req.headers.get('referer') || '/';
      const refUrl = new URL(referer);
      return redirect(refUrl.pathname);
    }

    // Remove habit
    if (pathname === '/remove' && method === 'POST') {
      const form = await parseFormBody(req);
      const { habitId } = form;
      if (habitId) {
        await removeHabit(habitId);
      }
      const referer = req.headers.get('referer') || '/';
      const refUrl = new URL(referer);
      return redirect(refUrl.pathname);
    }

    return new Response('Not Found', { status: 404 });
  },
});

