export type Holding = {
  id: string;
  symbol: string;
  amount: number;
  purchasePrice: number;
  addedAt: string;
};

export type PriceMap = Record<string, number>;

export type HoldingWithMetrics = Holding & {
  currentPrice: number;
  currentValue: number;
  costBasis: number;
  gainLoss: number;
  gainLossPercent: number;
};

export type PortfolioSummary = {
  holdings: HoldingWithMetrics[];
  totalValue: number;
  totalCost: number;
  totalGainLoss: number;
  totalGainLossPercent: number;
  allocations: { symbol: string; value: number; percent: number; color: string }[];
};

import type { Holding, PriceMap } from './types';

const HOLDINGS_PATH = 'data/holdings.json';
const PRICES_PATH = 'data/prices.json';

export const loadHoldings = async (): Promise<Holding[]> => {
  try {
    return await Bun.file(HOLDINGS_PATH).json();
  } catch {
    return [];
  }
};

export const saveHoldings = async (holdings: Holding[]): Promise<void> => {
  await Bun.write(HOLDINGS_PATH, JSON.stringify(holdings, null, 2));
};

export const loadPrices = async (): Promise<PriceMap> => {
  try {
    return await Bun.file(PRICES_PATH).json();
  } catch {
    return {};
  }
};

export const savePrices = async (prices: PriceMap): Promise<void> => {
  await Bun.write(PRICES_PATH, JSON.stringify(prices, null, 2));
};

export const addHolding = async (symbol: string, amount: number, purchasePrice: number): Promise<Holding> => {
  const holdings = await loadHoldings();
  const prices = await loadPrices();

  const upperSymbol = symbol.toUpperCase();
  const holding: Holding = {
    id: crypto.randomUUID(),
    symbol: upperSymbol,
    amount,
    purchasePrice,
    addedAt: new Date().toISOString(),
  };

  holdings.push(holding);
  await saveHoldings(holdings);

  // Set current price to purchase price if no price exists yet
  if (prices[upperSymbol] === undefined) {
    prices[upperSymbol] = purchasePrice;
    await savePrices(prices);
  }

  return holding;
};

export const removeHolding = async (id: string): Promise<boolean> => {
  const holdings = await loadHoldings();
  const index = holdings.findIndex((h) => h.id === id);
  if (index === -1) return false;

  holdings.splice(index, 1);
  await saveHoldings(holdings);
  return true;
};

export const updateHolding = async (
  id: string,
  updates: Partial<Pick<Holding, 'symbol' | 'amount' | 'purchasePrice'>>
): Promise<Holding | null> => {
  const holdings = await loadHoldings();
  const holding = holdings.find((h) => h.id === id);
  if (!holding) return null;

  if (updates.symbol !== undefined) holding.symbol = updates.symbol.toUpperCase();
  if (updates.amount !== undefined) holding.amount = updates.amount;
  if (updates.purchasePrice !== undefined) holding.purchasePrice = updates.purchasePrice;

  await saveHoldings(holdings);
  return holding;
};

export const updatePrice = async (symbol: string, price: number): Promise<void> => {
  const prices = await loadPrices();
  prices[symbol.toUpperCase()] = price;
  await savePrices(prices);
};

import type { Holding, PriceMap, HoldingWithMetrics, PortfolioSummary } from './types';
import { loadHoldings, loadPrices } from './data';

const COLORS = [
  '#f7931a', // BTC orange
  '#627eea', // ETH blue
  '#26a17b', // USDT green
  '#2775ca', // USDC blue
  '#e84142', // AVAX red
  '#8247e5', // MATIC purple
  '#00d395', // compound green
  '#ff007a', // UNI pink
  '#f0b90b', // BNB yellow
  '#345d9d', // LINK blue
  '#c2a633', // DOGE gold
  '#14f195', // SOL green
];

const computeMetrics = (holding: Holding, prices: PriceMap): HoldingWithMetrics => {
  const currentPrice = prices[holding.symbol] ?? holding.purchasePrice;
  const currentValue = holding.amount * currentPrice;
  const costBasis = holding.amount * holding.purchasePrice;
  const gainLoss = currentValue - costBasis;
  const gainLossPercent = costBasis > 0 ? (gainLoss / costBasis) * 100 : 0;

  return {
    ...holding,
    currentPrice,
    currentValue,
    costBasis,
    gainLoss,
    gainLossPercent,
  };
};

export const getPortfolioSummary = async (): Promise<PortfolioSummary> => {
  const holdings = await loadHoldings();
  const prices = await loadPrices();

  const enriched = holdings.map((h) => computeMetrics(h, prices));
  const totalValue = enriched.reduce((sum, h) => sum + h.currentValue, 0);
  const totalCost = enriched.reduce((sum, h) => sum + h.costBasis, 0);
  const totalGainLoss = totalValue - totalCost;
  const totalGainLossPercent = totalCost > 0 ? (totalGainLoss / totalCost) * 100 : 0;

  // Aggregate allocations by symbol
  const allocationMap = new Map<string, number>();
  for (const h of enriched) {
    allocationMap.set(h.symbol, (allocationMap.get(h.symbol) ?? 0) + h.currentValue);
  }

  const allocations = Array.from(allocationMap.entries()).map(([symbol, value], i) => ({
    symbol,
    value,
    percent: totalValue > 0 ? (value / totalValue) * 100 : 0,
    color: COLORS[i % COLORS.length],
  }));

  return {
    holdings: enriched,
    totalValue,
    totalCost,
    totalGainLoss,
    totalGainLossPercent,
    allocations,
  };
};

import { h } from '@plaited/temple';
import type { PortfolioSummary } from './types';

type SliceData = {
  symbol: string;
  percent: number;
  color: string;
};

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`;
};

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
};

export const renderPieChart = (allocations: PortfolioSummary['allocations']): string => {
  if (allocations.length === 0) {
    return h(
      'svg',
      { viewBox: '0 0 300 300', width: '300', height: '300' },
      h('circle', { cx: '150', cy: '150', r: '120', fill: '#2a2a3e' }),
      h(
        'text',
        { x: '150', y: '155', 'text-anchor': 'middle', fill: '#888', 'font-size': '14' },
        'No holdings'
      )
    );
  }

  // Single holding — full circle
  if (allocations.length === 1) {
    const a = allocations[0];
    return h(
      'svg',
      { viewBox: '0 0 440 300', width: '440', height: '300' },
      h('circle', { cx: '150', cy: '150', r: '120', fill: a.color }),
      ...renderLegend(allocations, 290)
    );
  }

  const slices: string[] = [];
  let currentAngle = 0;

  for (const a of allocations) {
    const sliceAngle = (a.percent / 100) * 360;
    if (sliceAngle < 0.5) continue; // skip tiny slices
    const path = describeArc(150, 150, 120, currentAngle, currentAngle + sliceAngle);
    slices.push(h('path', { d: path, fill: a.color, stroke: '#1a1a2e', 'stroke-width': '2' }));
    currentAngle += sliceAngle;
  }

  return h(
    'svg',
    { viewBox: '0 0 440 300', width: '440', height: '300' },
    ...slices,
    ...renderLegend(allocations, 290)
  );
};

const renderLegend = (allocations: PortfolioSummary['allocations'], startX: number): string[] => {
  const items: string[] = [];
  const visibleAllocations = allocations.slice(0, 10);

  visibleAllocations.forEach((a, i) => {
    const y = 20 + i * 26;
    items.push(
      h('rect', { x: String(startX), y: String(y), width: '16', height: '16', rx: '3', fill: a.color }),
      h(
        'text',
        { x: String(startX + 22), y: String(y + 13), fill: '#ccc', 'font-size': '12', 'font-family': 'monospace' },
        `${a.symbol} ${a.percent.toFixed(1)}%`
      )
    );
  });

  return items;
};

import { addHolding, removeHolding, updateHolding, updatePrice, loadHoldings, loadPrices } from './data';
import { getPortfolioSummary } from './portfolio';
import { renderDashboard } from './render';

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? '';

  if (contentType.includes('application/json')) {
    return req.json();
  }

  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text();
    const params = new URLSearchParams(text);
    return Object.fromEntries(params.entries());
  }

  return {};
};

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const redirect = (url: string): Response =>
  new Response(null, { status: 303, headers: { Location: url } });

const matchRoute = (
  method: string,
  pathname: string,
  targetMethod: string,
  pattern: string
): Record<string, string> | null => {
  if (method !== targetMethod) return null;

  const patternParts = pattern.split('/');
  const pathParts = pathname.split('/');
  if (patternParts.length !== pathParts.length) return null;

  const params: Record<string, string> = {};
  for (let i = 0; i < patternParts.length; i++) {
    if (patternParts[i].startsWith(':')) {
      params[patternParts[i].slice(1)] = pathParts[i];
    } else if (patternParts[i] !== pathParts[i]) {
      return null;
    }
  }
  return params;
};

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    try {
      // Dashboard
      if (method === 'GET' && pathname === '/') {
        const summary = await getPortfolioSummary();
        return htmlResponse(renderDashboard(summary));
      }

      // API: List holdings
      if (method === 'GET' && pathname === '/api/holdings') {
        const holdings = await loadHoldings();
        return jsonResponse(holdings);
      }

      // API: Add holding (JSON or form)
      if (method === 'POST' && pathname === '/api/holdings') {
        const body = await parseBody(req);
        const symbol = body.symbol;
        const amount = Number(body.amount);
        const purchasePrice = Number(body.purchasePrice);

        if (!symbol || isNaN(amount) || isNaN(purchasePrice) || amount <= 0 || purchasePrice < 0) {
          const isForm = (req.headers.get('content-type') ?? '').includes('form');
          if (isForm) return redirect('/');
          return jsonResponse({ error: 'Invalid input. Required: symbol (string), amount (>0), purchasePrice (>=0)' }, 400);
        }

        const holding = await addHolding(symbol, amount, purchasePrice);

        const isForm = (req.headers.get('content-type') ?? '').includes('form');
        if (isForm) return redirect('/');
        return jsonResponse(holding, 201);
      }

      // API: Delete holding
      let params = matchRoute(method, pathname, 'DELETE', '/api/holdings/:id');
      if (params) {
        const removed = await removeHolding(params.id);
        if (!removed) return jsonResponse({ error: 'Holding not found' }, 404);
        return jsonResponse({ success: true });
      }

      // Form-based delete (POST with /delete suffix)
      params = matchRoute(method, pathname, 'POST', '/api/holdings/:id/delete');
      if (params) {
        await removeHolding(params.id);
        return redirect('/');
      }

      // API: Update holding
      params = matchRoute(method, pathname, 'PUT', '/api/holdings/:id');
      if (params) {
        const body = await parseBody(req);
        const updates: Record<string, unknown> = {};
        if (body.symbol) updates.symbol = body.symbol;
        if (body.amount) updates.amount = Number(body.amount);
        if (body.purchasePrice) updates.purchasePrice = Number(body.purchasePrice);

        const updated = await updateHolding(params.id, updates as Parameters<typeof updateHolding>[1]);
        if (!updated) return jsonResponse({ error: 'Holding not found' }, 404);
        return jsonResponse(updated);
      }

      // API: Get prices
      if (method === 'GET' && pathname === '/api/prices') {
        const prices = await loadPrices();
        return jsonResponse(prices);
      }

      // API: Update price (PUT)
      params = matchRoute(method, pathname, 'PUT', '/api/prices/:symbol');
      if (params) {
        const body = await parseBody(req);
        const price = Number(body.price);
        if (isNaN(price) || price < 0) {
          return jsonResponse({ error: 'Invalid price' }, 400);
        }
        await updatePrice(params.symbol, price);
        return jsonResponse({ symbol: params.symbol.toUpperCase(), price });
      }

      // Form-based price update (POST)
      params = matchRoute(method, pathname, 'POST', '/api/prices/:symbol');
      if (params) {
        const body = await parseBody(req);
        const price = Number(body.price);
        if (!isNaN(price) && price >= 0) {
          await updatePrice(params.symbol, price);
        }
        return redirect('/');
      }

      return jsonResponse({ error: 'Not found' }, 404);
    } catch (err) {
      console.error('Server error:', err);
      return jsonResponse({ error: 'Internal server error' }, 500);
    }
  },
});

