export type Snippet = {
  id: string;
  title: string;
  language: string;
  tags: string[];
  code: string;
  createdAt: string;
};

export type SnippetInput = {
  title: string;
  language: string;
  tags: string | string[];
  code: string;
};

export type FilterParams = {
  lang?: string;
  tag?: string;
};

import type { Snippet, SnippetInput, FilterParams } from './types';

const DATA_PATH = 'data/snippets.json';

const readSnippets = async (): Promise<Snippet[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const writeSnippets = async (snippets: Snippet[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(snippets, null, 2));
};

const generateId = (): string =>
  crypto.randomUUID();

export const getAllSnippets = async (filters?: FilterParams): Promise<Snippet[]> => {
  let snippets = await readSnippets();

  if (filters?.lang) {
    const lang = filters.lang.toLowerCase();
    snippets = snippets.filter((s) => s.language.toLowerCase() === lang);
  }

  if (filters?.tag) {
    const tag = filters.tag.toLowerCase();
    snippets = snippets.filter((s) =>
      s.tags.some((t) => t.toLowerCase() === tag)
    );
  }

  return snippets.sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
  );
};

export const getSnippetById = async (id: string): Promise<Snippet | undefined> => {
  const snippets = await readSnippets();
  return snippets.find((s) => s.id === id);
};

export const createSnippet = async (input: SnippetInput): Promise<Snippet> => {
  const snippets = await readSnippets();
  const tags = Array.isArray(input.tags)
    ? input.tags
    : input.tags.split(',').map((t) => t.trim()).filter(Boolean);

  const snippet: Snippet = {
    id: generateId(),
    title: input.title.trim(),
    language: input.language.trim().toLowerCase(),
    tags,
    code: input.code,
    createdAt: new Date().toISOString(),
  };

  snippets.push(snippet);
  await writeSnippets(snippets);
  return snippet;
};

export const deleteSnippet = async (id: string): Promise<boolean> => {
  const snippets = await readSnippets();
  const index = snippets.findIndex((s) => s.id === id);
  if (index === -1) return false;
  snippets.splice(index, 1);
  await writeSnippets(snippets);
  return true;
};

export const getAllLanguages = async (): Promise<string[]> => {
  const snippets = await readSnippets();
  return [...new Set(snippets.map((s) => s.language))].sort();
};

export const getAllTags = async (): Promise<string[]> => {
  const snippets = await readSnippets();
  return [...new Set(snippets.flatMap((s) => s.tags))].sort();
};

