import {
  getAllSnippets,
  getSnippetById,
  createSnippet,
  deleteSnippet,
  getAllLanguages,
  getAllTags,
} from './store';
import { renderPage, renderSnippetDetail } from './render';
import type { SnippetInput } from './types';

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  params.forEach((v, k) => { result[k] = v; });
  return result;
};

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // GET / — main collection page with optional filters
    if (pathname === '/' && req.method === 'GET') {
      const lang = url.searchParams.get('lang') || undefined;
      const tag = url.searchParams.get('tag') || undefined;
      const [snippets, languages, tags] = await Promise.all([
        getAllSnippets({ lang, tag }),
        getAllLanguages(),
        getAllTags(),
      ]);
      return htmlResponse(renderPage(snippets, languages, tags, lang, tag));
    }

    // GET /snippet/:id — single snippet detail
    if (pathname.startsWith('/snippet/') && req.method === 'GET') {
      const id = pathname.slice('/snippet/'.length);
      const snippet = await getSnippetById(id);
      if (!snippet) return htmlResponse('<h1>Snippet not found</h1>', 404);
      return htmlResponse(renderSnippetDetail(snippet));
    }

    // POST /snippets — create new snippet (form or JSON)
    if (pathname === '/snippets' && req.method === 'POST') {
      const contentType = req.headers.get('content-type') || '';
      let input: SnippetInput;

      if (contentType.includes('application/json')) {
        input = await req.json() as SnippetInput;
      } else {
        const form = await parseFormBody(req);
        input = {
          title: form.title || '',
          language: form.language || '',
          tags: form.tags || '',
          code: form.code || '',
        };
      }

      if (!input.title || !input.language || !input.code) {
        return contentType.includes('application/json')
          ? jsonResponse({ error: 'title, language, and code are required' }, 400)
          : htmlResponse('<h1>Missing required fields</h1><a href="/">Go back</a>', 400);
      }

      const snippet = await createSnippet(input);

      if (contentType.includes('application/json')) {
        return jsonResponse(snippet, 201);
      }
      return Response.redirect('/', 303);
    }

    // DELETE /snippets/:id — delete a snippet
    if (pathname.startsWith('/snippets/') && req.method === 'DELETE') {
      const id = pathname.slice('/snippets/'.length);
      const deleted = await deleteSnippet(id);
      if (!deleted) return jsonResponse({ error: 'Snippet not found' }, 404);
      return jsonResponse({ ok: true });
    }

    // GET /api/snippets — JSON API
    if (pathname === '/api/snippets' && req.method === 'GET') {
      const lang = url.searchParams.get('lang') || undefined;
      const tag = url.searchParams.get('tag') || undefined;
      const snippets = await getAllSnippets({ lang, tag });
      return jsonResponse(snippets);
    }

    return htmlResponse('<h1>Not Found</h1>', 404);
  },
});

console.log(`Code Snippets server running at http://localhost:${server.port}`);

