export type Question = {
  id: string
  text: string
  options: [string, string, string, string]
  correctIndex: number
}

export type Quiz = {
  id: string
  title: string
  questions: Question[]
  createdAt: string
}

import type { Quiz } from './types'

const DATA_PATH = 'data/quizzes.json'

export const loadQuizzes = async (): Promise<Quiz[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveQuizzes = async (quizzes: Quiz[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(quizzes, null, 2))
}

export const getQuiz = async (id: string): Promise<Quiz | undefined> => {
  const quizzes = await loadQuizzes()
  return quizzes.find(q => q.id === id)
}

export const addQuiz = async (quiz: Quiz): Promise<void> => {
  const quizzes = await loadQuizzes()
  quizzes.push(quiz)
  await saveQuizzes(quizzes)
}

export const updateQuiz = async (updated: Quiz): Promise<void> => {
  const quizzes = await loadQuizzes()
  const idx = quizzes.findIndex(q => q.id === updated.id)
  if (idx >= 0) quizzes[idx] = updated
  await saveQuizzes(quizzes)
}

export const deleteQuiz = async (id: string): Promise<void> => {
  const quizzes = await loadQuizzes()
  await saveQuizzes(quizzes.filter(q => q.id !== id))
}

