export const renderResults = (quiz: Quiz, userAnswers: number[]): string => {
  const total = quiz.questions.length
  const correctCount = quiz.questions.reduce(
    (sum, q, i) => sum + (userAnswers[i] === q.correctIndex ? 1 : 0),
    0,
  )
  const pct = total > 0 ? Math.round((correctCount / total) * 100) : 0

  return ssr.render(layout(`Results: ${quiz.title}`,
    // Score header
    h('div', { style: css(s.card, { textAlign: 'center', padding: '40px 24px' }) },
      h('div', { style: { fontSize: '56px', fontWeight: '800', color: '#2563eb', lineHeight: '1' } },
        `${correctCount}/${total}`,
      ),
      h('p', { style: { margin: '12px 0 0', fontSize: '16px', color: '#6b7280' } },
        `You scored ${pct}% — ${correctCount} correct out of ${total}`,
      ),
    ),

    // Per-question breakdown
    h('h3', { style: { margin: '28px 0 16px', fontSize: '16px' } }, 'Question Breakdown'),
    ...quiz.questions.map((q, i) => {
      const isCorrect = userAnswers[i] === q.correctIndex
      const borderColor = isCorrect ? '#16a34a' : '#ef4444'
      const icon = isCorrect ? '\u2713' : '\u2717'
      const iconColor = isCorrect ? s.correct : s.incorrect

      return h('div', { style: css(s.card, { borderLeft: `4px solid ${borderColor}` }) },
        h('div', { style: { display: 'flex', gap: '12px', alignItems: 'flex-start' } },
          h('span', { style: { fontSize: '20px', fontWeight: '700', ...iconColor, flexShrink: '0', marginTop: '2px' } }, icon),
          h('div', { style: { flex: '1' } },
            h('p', { style: { margin: '0 0 8px', fontWeight: '600' } }, `Q${i + 1}. ${q.text}`),
            h('p', { style: { margin: '0 0 4px', fontSize: '14px' } },
              'Your answer: ',
              h('span', { style: isCorrect ? s.correct : s.incorrect },
                userAnswers[i] !== undefined && userAnswers[i] >= 0 && userAnswers[i] < 4
                  ? q.options[userAnswers[i]]
                  : '(no answer)',
              ),
            ),
            !isCorrect
              ? h('p', { style: { margin: '0', fontSize: '14px' } },
                  'Correct answer: ',
                  h('span', { style: s.correct }, q.options[q.correctIndex]),
                )
              : null,
          ),
        ),
      )
    }),

    // Actions
    h('div', { style: { display: 'flex', gap: '12px', marginTop: '24px' } },
      h('a', { href: `/take/${quiz.id}`, style: css(s.btn, s.btnPrimary) }, 'Retake Quiz'),
      h('a', { href: '/', style: css(s.btn, s.btnSecondary) }, 'Back to Quizzes'),
    ),
  ))
}

import { loadQuizzes, getQuiz, addQuiz, updateQuiz, deleteQuiz } from './store'
import {
  renderQuizList,
  renderCreateForm,
  renderEditQuiz,
  renderTakeQuestion,
  renderResults,
} from './render'
import type { Quiz, Question } from './types'

const html = (body: string) =>
  new Response(body, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (location: string) =>
  new Response(null, { status: 302, headers: { Location: location } })

const notFound = () => html('<h1>404 — Not Found</h1>')

const match = (path: string, pattern: string): Record<string, string> | null => {
  const patternParts = pattern.split('/')
  const pathParts = path.split('/')
  if (patternParts.length !== pathParts.length) return null
  const params: Record<string, string> = {}
  for (let i = 0; i < patternParts.length; i++) {
    if (patternParts[i].startsWith(':')) {
      params[patternParts[i].slice(1)] = pathParts[i]
    } else if (patternParts[i] !== pathParts[i]) {
      return null
    }
  }
  return params
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method
    let params: Record<string, string> | null

    // ── GET / ── list quizzes
    if (path === '/' && method === 'GET') {
      const quizzes = await loadQuizzes()
      return html(renderQuizList(quizzes))
    }

    // ── GET /create ── create form
    if (path === '/create' && method === 'GET') {
      return html(renderCreateForm())
    }

    // ── POST /create ── save new quiz
    if (path === '/create' && method === 'POST') {
      const form = await req.formData()
      const title = (form.get('title') as string)?.trim()
      if (!title) return redirect('/create')
      const quiz: Quiz = {
        id: crypto.randomUUID(),
        title,
        questions: [],
        createdAt: new Date().toISOString(),
      }
      await addQuiz(quiz)
      return redirect(`/edit/${quiz.id}`)
    }

    // ── GET /edit/:id ── edit quiz
    if ((params = match(path, '/edit/:id')) && method === 'GET') {
      const quiz = await getQuiz(params.id)
      if (!quiz) return notFound()
      return html(renderEditQuiz(quiz))
    }

    // ── POST /edit/:id/add-question ── add a question
    if ((params = match(path, '/edit/:id/add-question')) && method === 'POST') {
      const quiz = await getQuiz(params.id)
      if (!quiz) return notFound()
      const form = await req.formData()
      const text = (form.get('text') as string)?.trim()
      const options: [string, string, string, string] = [
        (form.get('option0') as string)?.trim() || '',
        (form.get('option1') as string)?.trim() || '',
        (form.get('option2') as string)?.trim() || '',
        (form.get('option3') as string)?.trim() || '',
      ]
      const correctIndex = parseInt(form.get('correct') as string, 10)
      if (!text || options.some(o => !o) || isNaN(correctIndex)) {
        return redirect(`/edit/${quiz.id}`)
      }
      const question: Question = {
        id: crypto.randomUUID(),
        text,
        options,
        correctIndex,
      }
      quiz.questions.push(question)
      await updateQuiz(quiz)
      return redirect(`/edit/${quiz.id}`)
    }

    // ── POST /edit/:id/remove/:qid ── remove a question
    if ((params = match(path, '/edit/:id/remove/:qid')) && method === 'POST') {
      const quiz = await getQuiz(params.id)
      if (!quiz) return notFound()
      quiz.questions = quiz.questions.filter(q => q.id !== params!.qid)
      await updateQuiz(quiz)
      return redirect(`/edit/${quiz.id}`)
    }

    // ── POST /delete/:id ── delete quiz
    if ((params = match(path, '/delete/:id')) && method === 'POST') {
      await deleteQuiz(params.id)
      return redirect('/')
    }

    // ── GET /take/:id ── start or continue taking a quiz
    if ((params = match(path, '/take/:id')) && method === 'GET') {
      const quiz = await getQuiz(params.id)
      if (!quiz || quiz.questions.length === 0) return notFound()
      const qIndex = parseInt(url.searchParams.get('q') || '0', 10)
      const answers = url.searchParams.get('a') || ''
      if (qIndex < 0 || qIndex >= quiz.questions.length) {
        return redirect(`/results/${quiz.id}?a=${answers}`)
      }
      return html(renderTakeQuestion(quiz, qIndex, answers))
    }

    // ── POST /take/:id ── submit an answer
    if ((params = match(path, '/take/:id')) && method === 'POST') {
      const quiz = await getQuiz(params.id)
      if (!quiz) return notFound()
      const form = await req.formData()
      const qIndex = parseInt(form.get('q') as string, 10)
      const selected = form.get('selected') as string
      const prevAnswers = (form.get('answers') as string) || ''

      const newAnswers = prevAnswers ? `${prevAnswers},${selected}` : selected
      const nextQ = qIndex + 1

      if (nextQ >= quiz.questions.length) {
        return redirect(`/results/${quiz.id}?a=${newAnswers}`)
      }
      return redirect(`/take/${quiz.id}?q=${nextQ}&a=${newAnswers}`)
    }

    // ── GET /results/:id ── show results
    if ((params = match(path, '/results/:id')) && method === 'GET') {
      const quiz = await getQuiz(params.id)
      if (!quiz) return notFound()
      const answersStr = url.searchParams.get('a') || ''
      const userAnswers = answersStr.split(',').map(s => parseInt(s, 10))
      return html(renderResults(quiz, userAnswers))
    }

    return notFound()
  },
})

console.log(`Quiz Builder running at http://localhost:${server.port}`)
